public class SyncedBlockEntity extends BlockEntity {
    private int syncedValue = 0;

    @Override
    public void markDirty() {
        super.markDirty();
        if (world != null && !world.isClient) {
            world.updateListeners(pos, getCachedState(), getCachedState(), Block.NOTIFY_ALL);
        }
    }

    @Override
    public NbtCompound toInitialChunkDataNbt() {
        return createNbt();
    }

    public int getSyncedValue() { return syncedValue; }
    public void setSyncedValue(int value) { this.syncedValue = value; markDirty(); }
}

public class CustomEntity extends LivingEntity {
    private static final TrackedData<Integer> CUSTOM_DATA = DataTracker.registerData(CustomEntity.class, TrackedDataHandlerRegistry.INTEGER);

    @Override
    protected void initDataTracker() {
        this.dataTracker.startTracking(CUSTOM_DATA, 0);
    }

    public int getCustomData() {
        return this.dataTracker.get(CUSTOM_DATA);
    }

    public void setCustomData(int value) {
        this.dataTracker.set(CUSTOM_DATA, value);
    }
}

public class CustomTrackedDataHandler implements TrackedDataHandler<CustomData> {
    @Override
    public void write(PacketByteBuf buf, CustomData value) {
        buf.writeInt(value.value());
        buf.writeString(value.name());
    }

    @Override
    public CustomData read(PacketByteBuf buf) {
        return new CustomData(buf.readInt(), buf.readString());
    }

    @Override
    public CustomData copy(CustomData value) {
        return new CustomData(value.value(), value.name());
    }
}

public class PlayerDataSync {
    private static final Identifier SYNC_PACKET = new Identifier("modid", "player_sync");

    public static void syncAllPlayers(ServerWorld world) {
        PacketByteBuf buf = PacketByteBufs.create();
        buf.writeInt(world.getPlayers().size());
        for (ServerPlayerEntity player : world.getPlayers()) {
            buf.writeUuid(player.getUuid());
            buf.writeInt(player.experienceLevel);
        }

        for (ServerPlayerEntity player : world.getPlayers()) {
            ServerPlayNetworking.send(player, SYNC_PACKET, buf);
        }
    }
}

public class CustomAbilityComponent implements Component {
    private int energy = 100;
    private int maxEnergy = 100;

    @Override
    public void readFromNbt(NbtCompound nbt) {
        energy = nbt.getInt("Energy");
    }

    @Override
    public void writeToNbt(NbtCompound nbt) {
        nbt.putInt("Energy", energy);
    }

    public void sync(ServerPlayerEntity player) {
        ComponentChanges changes = ComponentChanges.builder()
            .add(ModComponents.CUSTOM_ABILITY, this)
            .build();
        player.networkHandler.sendPacket(new ComponentUpdateS2CPacket(player.getId(), changes));
    }
}

public class IncrementalSyncManager {
    private final Map<Identifier, Object> lastSynced = new HashMap<>();

    public void syncIfChanged(ServerPlayerEntity player, Identifier key, Object newValue) {
        Object oldValue = lastSynced.get(key);
        if (!Objects.equals(oldValue, newValue)) {
            sendUpdate(player, key, newValue);
            lastSynced.put(key, newValue);
        }
    }

    private void sendUpdate(ServerPlayerEntity player, Identifier key, Object value) {
        PacketByteBuf buf = PacketByteBufs.create();
        buf.writeIdentifier(key);
        // 写入 value
        ServerPlayNetworking.send(player, UPDATE_PACKET, buf);
    }
}

public class TimeSyncManager {
    public static void syncTime(ServerWorld world, ServerPlayerEntity player) {
        PacketByteBuf buf = PacketByteBufs.create();
        buf.writeLong(world.getTime());
        buf.writeLong(world.getTimeOfDay());
        buf.writeBoolean(world.isRaining());
        buf.writeInt(world.getThunderTime());
        ServerPlayNetworking.send(player, TIME_SYNC_PACKET, buf);
    }
}
